<script>
import {
  IonPage,
  IonContent,
  IonInput,
  IonItem,
  IonLabel,
  IonCard,
  IonButton,
  IonButtons,
  IonModal,
  IonTitle,
  IonToolbar,
  IonHeader,
  IonCol,
  IonRow,
  IonGrid,
  IonIcon,
} from "@ionic/vue";
import HeaderReturn from "@/components/header/HeaderReturn.vue";
import { defineComponent } from "vue";
import Refresher from "@/components/refresher/Refresher.vue";
import BenefitCard from "@/views/services/benefits/components/BenefitCard.vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import axios from "axios";
import { GlobalConstants } from "@/config/constants";
import { toastController } from "@ionic/vue";

export default defineComponent({
  components: {
    IonPage,
    IonContent,
    IonInput,
    IonItem,
    HeaderReturn,
    IonLabel,
    Refresher,
    IonCard,
    BenefitCard,
    IonButton,
    IonButtons,
    IonModal,
    IonTitle,
    IonToolbar,
    IonHeader,
    IonCol,
    IonRow,
    IonGrid,
    IonIcon,
  },
  setup() {
    return {
      router: useRouter(),
      store: useStore(),
    };
  },
  data() {
    const currentDate = new Date();
    const formattedDate = currentDate.toISOString().split("T")[0];

    return {
      results: [],
      headerTitle: "Benefits",
      selectedDateFrom: formattedDate,
      selectedDateTo: formattedDate,
      isModalVisible: false,
      selectedResult: null,
      isOpen: false,
      theme: {},
      loading: true,
      totalRec: 0,
      paygradeId: 0,
      empNumber: "",
      standardBenefits: null,
      addedBenefits: null,
    };
  },

  methods: {
    // Expiration of token
    async checkTokenExpiration() {
      const storedToken = localStorage.getItem("token");

      if (!storedToken) {
        console.error("Token not available.");
        console.log("Token is missing. Redirecting to login...");
        this.router.push("/login");
        return;
      }

      const tokenData = JSON.parse(atob(storedToken.split(".")[1]));
      const expirationTime = tokenData.exp * 1000;

      if (Date.now() > expirationTime) {
        console.log("Token expired. Redirecting to login...");
        this.router.push("/login");
      }
    },

    async fetchPaygrade() {
      try {
        await this.checkTokenExpiration();
        const baseURL = localStorage.getItem("baseUrl");
        const storedToken = localStorage.getItem("token");

        const headers = {
          Authorization: `Bearer ${storedToken}`,
        };

        const api =
          baseURL + `api/v2/ess/employee/benefit-package/${this.empNumber}`;

        const dataResponse = await axios.get(api, { headers });

        this.paygradeId = dataResponse.data.data.id;
        this.fetchRequest();
      } catch (error) {
        console.log(error.response?.data?.error?.message);
      }
    },

    async fetchRequest() {
      try {
        this.store.commit("loader/updateLoader", true);
        const baseURL = localStorage.getItem("baseUrl");
        await this.checkTokenExpiration();

        const storedToken = localStorage.getItem("token");

        const headers = {
          Authorization: `Bearer ${storedToken}`,
        };

        const api =
          baseURL +
          `api/v2/benefit-packages/${this.paygradeId}?limit=50&offset=0`;
        const dataResponse = await axios.get(api, { headers });

        const { id, payGradeName, jobCategoryName, name, packageItems } =
          dataResponse.data.data;

        const mappedPackageItems = packageItems.map((item) => ({
          benefitType: item.benefitType,
          benefitName: item.benefitName.trim(),
          benefitCode: item.benefitCode,
        }));

        this.standardBenefits = mappedPackageItems.filter(
          (item) => item.benefitType === "Standards Benefits"
        );

        this.addedBenefits = mappedPackageItems.filter(
          (item) =>
            item.benefitType === "Added Regular Benefits" ||
            item.benefitType === "Irregular Benefits"
        );

        this.id = id;
        this.payGradeName = payGradeName;
        this.jobCategoryName = jobCategoryName;
        this.name = name;
        this.totalRec = mappedPackageItems.length;

        this.store.commit("loader/updateLoader", false);
      } catch (error) {
        this.store.commit("loader/updateLoader", false);
        console.error("Error fetching benefit package: ", error);

        // Show error message if available
        this.showErrorMessage(
          error.response?.data?.error?.message ||
            "An error occurred while fetching the data."
        );
      }
    },

    async showErrorMessage(message) {
      try {
        const toast = await toastController.create({
          message: message,
          duration: 3000,
          position: "top",
          color: "light",
          buttons: [
            {
              icon: "close-outline",
              role: "cancel",
            },
          ],
        });
        await toast.present();
      } catch (error) {
        console.error("Error displaying toast:", error);
      }
    },

    handleView(result) {
      this.selectedResult = result;
      console.log("Selected", this.selectedResult);
      console.log("Selected", result);
      this.isOpen = true;
    },

    setOpen(val) {
      this.isOpen = val;
    },
    fetchTheme() {
      const storedThemeData = localStorage.getItem("themeData");

      const themeData = storedThemeData ? JSON.parse(storedThemeData) : {};

      this.theme = themeData;
    },
  },
  created() {
    this.empNumber = localStorage.getItem("empNumber");
    this.checkTokenExpiration();
    this.fetchTheme();
    this.fetchPaygrade();

    this.loading = false;
    console.log(this.results.length);
  },
});
</script>

